import{_ as t,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3036_文曄/20260512/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/3036_文曄/20260512/F06_存貨與債務穩定度審計.md"}'),i={name:"審計報告庫/財務審計/3036_文曄/20260512/F06_存貨與債務穩定度審計.md"};function e(n,a,s,h,d,c){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="f06-存貨與債務穩定度審計-財務審計專家-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務審計專家-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨2,598億YoY+61%，週轉288天為四年最長。流動比125%速動比55%偏低，但現金循環-11天靠供應商融資。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>存貨規模</strong>：905億(2022)→957億(2023,+5.7%)→1,609億(2024,+68.2%)→2,598億(2025,+61.4%)。併購+AI需求驅動存貨快速擴張。</li><li><strong>流動性指標</strong>：流動比125%(2025)低於200%理想值；速動比55%低於100%警戒線。存貨佔流動資產55.9%為主要壓力來源。</li><li><strong>債務結構</strong>：短期借款256億+長期借款237億=總借款493億。現金281億，淨負債212億。短期借款從354億降至256億，債務壓力改善。</li><li><strong>診斷見解</strong>：存貨快速擴張但現金循環-11天(供應商融資352天覆蓋)，短期償債壓力可控。速動比偏低為通路商結構性特徵。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-存貨結構與週轉分析" tabindex="-1">1. 存貨結構與週轉分析 <a class="header-anchor" href="#_1-存貨結構與週轉分析" aria-label="Permalink to &quot;1. 存貨結構與週轉分析&quot;">​</a></h3><ul><li><strong>存貨暴增61%</strong>：2025年底存貨2,598億，YoY+61.4%，主要反映(1)AI產品備貨(2)營收成長帶動採購增加。週轉天數從234天拉長至288天(+23%)，為四年最高。</li><li><strong>通路商存貨特性</strong>：半導體通路需備齊數萬SKU，存貨天數200-300天為行業常態。288天偏高但在合理區間。需關注若AI需求降溫，存貨去化壓力。</li><li><strong>跌價風險</strong>：通路商存貨為「可轉售半導體」，跌價風險低於製造業。但若技術迭代(如舊款IC)導致過時，仍需提列減損。</li></ul><h3 id="_2-流動性與償債能力" tabindex="-1">2. 流動性與償債能力 <a class="header-anchor" href="#_2-流動性與償債能力" aria-label="Permalink to &quot;2. 流動性與償債能力&quot;">​</a></h3><ul><li><strong>速動比55%</strong>：流動資產464億-存貨260億=速動資產204億，除以流動負債370億=55.2%。低於100%代表若存貨無法變現，短期債務將面臨壓力。</li><li><strong>現金覆蓋</strong>：現金281億 vs 短期借款256億=1.1倍，現金可完全覆蓋短債。但扣除營運資金需求後，實質緩衝有限。</li><li><strong>債務改善</strong>：短期借款從354億(2024)降至256億(-28%)，長期借款從634億降至237億(-63%)。併購後快速去槓桿。</li></ul><h3 id="_3-供應商融資優勢" tabindex="-1">3. 供應商融資優勢 <a class="header-anchor" href="#_3-供應商融資優勢" aria-label="Permalink to &quot;3. 供應商融資優勢&quot;">​</a></h3><ul><li><strong>DPO 352天</strong>：文曄付款給供應商平均352天(近一年)，遠長於收款天數53天。代表公司長期佔用供應商資金作為營運資本。</li><li><strong>現金循環-11天</strong>：DPO(352)&gt;DIO(288)+DSO(53)=341天，現金循環為負，代表營運資金完全由供應商融資支應。此為通路商龍頭之結構性優勢。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>存貨週轉惡化</strong>：存貨天數從189天(2023)拉長至288天(+52%)，增速遠超營收成長。若AI需求放緩或半導體庫存修正，2,600億存貨面臨跌價壓力。</li><li><strong>速動比55%偏低</strong>：低於100%警戒線，代表存貨佔流動資產過半。若突發性資金需求(如供應商縮短帳期)，流動性可能緊張。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>現金循環-11天為競爭優勢</strong>：靠供應商融資352天，完全覆蓋營運資金需求。代表文曄在產業鏈中議價能力強，可無成本使用供應商資金。</li><li><strong>債務快速去化</strong>：短期借款從354億降至256億(-28%)，長期從634億降至237億(-63%)。併購後財務結構迅速改善，利息覆蓋壓力減輕。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>存貨快速擴張需關注去化風險，但現金循環-11天提供緩衝。速動比偏低為結構性特徵，不構成即時流動性風險。關鍵觀察AI需求能否維持存貨周轉效率。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (inventory_check 3036 2022 2025)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet + TaiwanStockFinancialStatements</li><li><strong>查詢參數</strong>：stock_id=3036, start=2022-01-01, end=2025-12-31</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const u=t(i,[["render",e]]);export{_ as __pageData,u as default};
